// src/i18n/index.js
import React, { createContext, useContext, useEffect, useMemo, useState } from "react";
import AsyncStorage from "@react-native-async-storage/async-storage";

const STORAGE_KEY = "app_lang";

const DICT = {
  fr: {
    // Language labels
    lang: {
      fr: "Français",
      en: "English",
    },

    // Home
    home: {
      verified: "Vérifié",
      officialControl: "Contrôle officiel",
    },

    // Modal
    modal: {
      enterSecretCode: "Entrer le code secret",
      placeholder: "••••••",
    },

    // Common buttons / labels
    common: {
      cancel: "Annuler",
      confirm: "Confirmer",
      back: "Retour",
    },

    // Official control screen (Taxi details)
    official: {
      statusAuthorized: "VÉHICULE AUTORISÉ",

      vehicle: {
        title: "Identification du Véhicule (Carte Grise)",
        plate: "Immatriculation",
        model: "Marque & Modèle",
        owner: "Propriétaire",
      },

      licence: {
        title: "Autorisation d'Exercer (Licence)",
        number: "Numéro de Licence",
        validity: "Validité",
        zone: "Zone",
        doorNumber: "Numéro de Portière",
      },

      driver: {
        title: "Profil du Chauffeur (Permis & CNI)",
        name: "Noms",
        permit: "Numéro Permis",
        category: "Catégorie",
        cni: "Numéro CNI",
      },

      insurance: {
        title: "Couverture Risques (Assurance)",
        company: "Compagnie",
        expiry: "Expiration",
        status: "Statut",
      },
    },
  },

  // ===================== ENGLISH SECTION =====================
  en: {
    lang: {
      fr: "French",
      en: "English",
    },

    home: {
      verified: "Verified",
      officialControl: "Official control",
    },

    modal: {
      enterSecretCode: "Enter Secret code",
      placeholder: "••••••",
    },

    common: {
      cancel: "Cancel",
      confirm: "Confirm",
      back: "Back",
    },
// EN
official: {
  statusAuthorized: "AUTHORIZED VEHICLE",
  vehicle: { title: "Vehicle identification", subtitle: "Registration", plate: "Plate number", model: "Brand & model", owner: "Owner" },
  licence: { title: "Operating authorization", subtitle: "Licence", number: "Licence number", validity: "Validity", zone: "Zone", doorNumber: "Door number", active: "Active" },
  driver: { title: "Driver profile", subtitle: "Permit & ID", permit: "Permit number", category: "Category", cni: "ID number" },
  insurance: { title: "Risk coverage", subtitle: "Insurance", company: "Company", expiry: "Expiry" },
},
common: { back: "Back" }

  },
};

const LanguageContext = createContext(null);

function getByPath(obj, path) {
  return path.split(".").reduce((acc, key) => (acc ? acc[key] : undefined), obj);
}

export function LanguageProvider({ children }) {
  const [lang, setLang] = useState("fr");

  // Load saved language once
  useEffect(() => {
    (async () => {
      try {
        const saved = await AsyncStorage.getItem(STORAGE_KEY);
        if (saved === "fr" || saved === "en") setLang(saved);
      } catch (e) {
        // ignore
      }
    })();
  }, []);

  // Save language whenever it changes
  useEffect(() => {
    (async () => {
      try {
        await AsyncStorage.setItem(STORAGE_KEY, lang);
      } catch (e) {
        // ignore
      }
    })();
  }, [lang]);

  const t = useMemo(() => {
    return (key) => {
      const value = getByPath(DICT[lang], key);
      return value ?? key; // fallback
    };
  }, [lang]);

  const value = useMemo(() => ({ lang, setLang, t }), [lang, t]);

  return <LanguageContext.Provider value={value}>{children}</LanguageContext.Provider>;
}

export function useTranslation() {
  const ctx = useContext(LanguageContext);
  if (!ctx) throw new Error("useTranslation must be used inside <LanguageProvider>");
  return ctx; // { lang, setLang, t }
}
